411: 
412:         ConsumerGroupMember member = new ConsumerGroupMember.Builder(memberId)
413:             .setState(MemberState.STABLE)
414:             .setMemberEpoch(100)
415:             .setPreviousMemberEpoch(99)
416:             .setRebalanceTimeoutMs(5000)
417:             .setClientId(DEFAULT_CLIENT_ID)
418:             .setClientHost(DEFAULT_CLIENT_ADDRESS.toString())
419:             .setSubscribedTopicNames(List.of("foo", "bar"))
420:             .setServerAssignorName("range")
421:             .setAssignedPartitions(mkAssignment(mkTopicAssignment(fooTopicId, 1, 2, 3)))
422:             .build();
423: 
424:         context.replay(GroupCoordinatorRecordHelpers.newConsumerGroupMemberSubscriptionRecord(groupId, member));
425: 
426:         context.replay(GroupCoordinatorRecordHelpers.newConsumerGroupEpochRecord(groupId, 100, 0));
427: 
428:         context.replay(GroupCoordinatorRecordHelpers.newConsumerGroupTargetAssignmentRecord(groupId, memberId, mkAssignment(
429:             mkTopicAssignment(fooTopicId, 1, 2, 3)
430:         )));
431: 
432:         context.replay(GroupCoordinatorRecordHelpers.newConsumerGroupTargetAssignmentEpochRecord(groupId, 100));
433: 
434:         context.replay(GroupCoordinatorRecordHelpers.newConsumerGroupCurrentAssignmentRecord(groupId, member));
435: 
436:         // Member epoch is greater than the expected epoch.
437:         assertThrows(FencedMemberEpochException.class, () ->
438:             context.consumerGroupHeartbeat(
439:                 new ConsumerGroupHeartbeatRequestData()
440:                     .setGroupId(groupId)
441:                     .setMemberId(memberId)
442:                     .setMemberEpoch(200)
443:                     .setRebalanceTimeoutMs(5000)
444:                     .setSubscribedTopicNames(List.of("foo", "bar"))));
445: 
446:         // Member epoch is smaller than the expected epoch.
447:         assertThrows(FencedMemberEpochException.class, () ->
448:             context.consumerGroupHeartbeat(
449:                 new ConsumerGroupHeartbeatRequestData()
450:                     .setGroupId(groupId)
451:                     .setMemberId(memberId)
452:                     .setMemberEpoch(50)
453:                     .setRebalanceTimeoutMs(5000)
454:                     .setSubscribedTopicNames(List.of("foo", "bar"))));
455: 
456:         // Member joins with previous epoch but without providing partitions.
457:         assertThrows(FencedMemberEpochException.class, () ->
458:             context.consumerGroupHeartbeat(
459:                 new ConsumerGroupHeartbeatRequestData()
460:                     .setGroupId(groupId)
461:                     .setMemberId(memberId)
462:                     .setMemberEpoch(99)
463:                     .setRebalanceTimeoutMs(5000)
464:                     .setSubscribedTopicNames(List.of("foo", "bar"))));
465: 
466:         // Member joins with previous epoch and has a subset of the owned partitions. This
467:         // is accepted as the response with the bumped epoch may have been lost. In this
468:         // case, we provide back the correct epoch to the member.
469:         CoordinatorResult<ConsumerGroupHeartbeatResponseData, CoordinatorRecord> result = context.consumerGroupHeartbeat(
470:             new ConsumerGroupHeartbeatRequestData()
471:                 .setGroupId(groupId)
472:                 .setMemberId(memberId)
473:                 .setMemberEpoch(99)
474:                 .setRebalanceTimeoutMs(5000)
475:                 .setSubscribedTopicNames(List.of("foo", "bar"))
476:                 .setTopicPartitions(List.of(new ConsumerGroupHeartbeatRequestData.TopicPartitions()
477:                     .setTopicId(fooTopicId)
478:                     .setPartitions(List.of(1, 2)))));
479:         assertEquals(100, result.response().memberEpoch());
480:     }
